#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, index;
        scanf("%d", &n);
        int arr[15];
        for (int i = 0; i < n; ++i) {
            scanf("%d", &arr[i]);
        }
        scanf("%d", &index);
        int *ptr = &arr[index - 1];
        printf("%d\n", *ptr);
        if (index > 1) {
            ptr--;
            printf("%d\n", *ptr);
        }
    }
    return 0;
}

