#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    while (T--) {
        int n, index;
        cin >> n;
        vector<int> arr(n);
        for (int i = 0; i < n; ++i) cin >> arr[i];
        cin >> index;
        int *ptr = &arr[index - 1];
        cout << *ptr << '\n';
        if (index > 1) {
            --ptr;
            cout << *ptr << '\n';
        }
    }
    return 0;
}

